const db = require('../config/db/mysql');
//获取指定笔记信息
function getNote(id) {
    return new Promise((resolve, reject) => {
        let sql = 'select id,date,title,preview,imgs,content,classs from notes where shows = 1 and id = ? ';
        try {
            db.query(sql, id, (err, results) => {
                if (err) {
                    reject('0');
                }
                if (results.length > 0) {
                    resolve(results[0]);
                }
            });
        }
        catch {
            reject('0');
        }
    });
}
