//按时间顺序获取笔记列表
function getNoteLists() {
    return new Promise((resolve, reject) => {
        let sql = `SELECT id, date, title, preview, imgs, classs  
                    FROM notes  
                    WHERE shows = 1  
                    ORDER BY date DESC;`;
        try {
            db.query(sql, (err, results) => {
                if (err) {
                    reject('0');
                }
                if (results.length > 0) {
                    resolve(results);
                }
            });
        }
        catch {
            reject('0');
        }
    });
}
