//插入视频
async function setDtVideo(id, videoIndex, videoName) {
    let video_src = process.env.dtVideoSrc;
    if (!video_src) {
        return new Error('请先配置视频目录');
    }
    try {
        await prisma_1.prisma.dt_video.create({
            data: {
                dt_id: id,
                video_index: videoIndex,
                video_src: video_src,
                video_name: videoName,
            },
        });
    }
    catch {
        return false;
    }
    return true;
}
//插入图片
async function setImgDt(id, imgIndex, imgName) {
    let img_src = process.env.dtImgSrc;
    if (!img_src) {
        return new Error('请先配置视频目录');
    }
    try {
        await prisma_1.prisma.dt_img.create({
            data: {
                dt_id: id,
                img_index: imgIndex,
                img_src: img_src,
                img_name: imgName,
            },
        });
    }
    catch {
        return false;
    }
    return true;
}
